import React from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { actionCreator } from './redux/actionCreator'

function App () {
  const dispatch = useDispatch()
  const state = useSelector(state => state)

  const handleUpgradeClick = () => {
    if (state.player.gold >= state.player.upgradeCost) {
      dispatch(actionCreator.upgrade())
    }
  }

  const handleAttackClick = () => {
    dispatch(actionCreator.damageMonster(state.player.damage))
  }

  return (
    <div>
      <h1>Idle Monster</h1>

      <fieldset>
        <legend>Monster</legend>
        <table>
          <thead>
          <tr>
            <th>{`Monster Name`}</th>
            <th>{`Monster Health`}</th>
          </tr>
          </thead>
          <tbody>
          <tr>
            <td>{state.currentMonster.name}</td>
            <td>{state.currentMonster.health}</td>
          </tr>
          </tbody>
        </table>
      </fieldset>

      <fieldset>
        <legend>Level</legend>
        <table>
          <thead>
          <tr>
            <th>{`Level`}</th>
            <th>{`Kill Amount`}</th>
            <th>{`Level Upgrade Require`}</th>
          </tr>
          </thead>
          <tbody>
          <tr>
            <td>{state.player.level}</td>
            <td>{state.player.levelKillAmount}</td>
            <td>{state.player.levelKillAmountRequire}</td>
          </tr>
          </tbody>
        </table>
      </fieldset>

      <fieldset>
        <legend>Player</legend>
        <table>
          <thead>
          <tr>
            <th>{`Gold`}</th>
            <th>{`Upgrade Cost`}</th>
            <th>{`Damage`}</th>
          </tr>
          </thead>
          <tbody>
          <tr>
            <td>{state.player.gold}</td>
            <td>{state.player.upgradeCost}</td>
            <td>{state.player.damage}</td>
          </tr>
          </tbody>
        </table>
      </fieldset>

      <button
        onClick={handleUpgradeClick}
        disabled={state.player.gold < state.player.upgradeCost}
      >
        Upgrade
      </button>
      <button
        onClick={handleAttackClick}
      >
        Attack
      </button>
    </div>
  )
}

export default App
